PART = '<!doctype html><html lang="zh-CN" data-theme="light"><head><meta charset=utf-8><meta name=viewport content="width=device-width,initial-scale=1"><title>FinAnalysis</title><style>\n:root{--bg:#f8f9fb;--card:#fff;--soft:#f2f4f6;--line:#e5e7eb;--text:#111827;--muted:#6b7280;--pri:#111827;--up:__UP__;--down:__DOWN__}[data-theme=dark]{--bg:#0d1117;--card:#111827;--soft:#1f2937;--line:#334155;--text:#e5e7eb;--muted:#a7b0bf;--pri:#f9fafb}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans SC",Arial,sans-serif}button,input,select{font:inherit;color:inherit}a{color:inherit;text-decoration:none}p,b,a,td{overflow-wrap:anywhere}.top{position:sticky;top:0;z-index:5;background:var(--card);border-bottom:1px solid var(--line)}.top>div{max-width:1440px;margin:auto;min-height:62px;padding:0 22px;display:flex;gap:10px;align-items:center;justify-content:space-between}.brand{font-weight:850;font-size:20px}.brand:before{content:"FA";display:inline-grid;place-items:center;width:32px;height:32px;margin-right:9px;border-radius:8px;background:var(--pri);color:var(--bg);font-size:13px}nav,.act{display:flex;gap:6px;align-items:center}button{border:1px solid var(--line);background:var(--card);border-radius:7px;min-height:38px;padding:0 10px;cursor:pointer}nav button,.side button,.mnav button{border:0;background:transparent;color:var(--muted)}button.active,.primary{background:var(--pri)!important;color:var(--bg)!important;border-color:var(--pri)}#q{height:38px;width:min(250px,28vw);border:1px solid var(--line);border-radius:7px;background:var(--soft);padding:0 10px}.shell{max-width:1440px;margin:auto;display:grid;grid-template-columns:230px minmax(0,1fr)}.side{position:sticky;top:63px;height:calc(100vh - 63px);border-right:1px solid var(--line);padding:14px}.side button{width:100%;min-height:42px;text-align:left;border-radius:7px}main{min-width:0;padding:24px}.view{display:none}.view.active{display:block}.wrap{max-width:1180px;margin:auto;min-width:0}.analysis .wrap{max-width:1080px}.head{display:flex;justify-content:space-between;gap:14px;margin-bottom:16px}.eyebrow{margin:0 0 6px;color:var(--muted);font-size:12px;text-transform:uppercase;font-weight:800}h1{font-size:30px;line-height:1.15;margin:0 0 6px}h2{font-size:19px;margin:0 0 12px}.muted{color:var(--muted)}.grid{display:grid;gap:14px;min-width:0}.kpis,.c3{grid-template-columns:repeat(3,minmax(0,1fr))}.c2{grid-template-columns:minmax(0,1.45fr) minmax(300px,.9fr)}.deep{grid-template-columns:minmax(0,1fr) 320px}.card,.item{background:var(--card);border:1px solid var(--line);border-radius:8px;padding:14px;min-width:0;overflow:hidden}.row{display:flex;justify-content:space-between;gap:12px;align-items:flex-start}.val{font-size:30px;font-weight:850;line-height:1.08}.up{color:var(--up)}.down{color:var(--down)}.pill{display:inline-flex;min-height:24px;align-items:center;border-radius:999px;padding:0 8px;background:#dbeafe;color:#1d4ed8;font-size:12px;font-weight:800;white-space:nowrap}.high{background:#fee2e2;color:#991b1b}.medium{background:#fff3cd;color:#7a4d00}.low{background:#d1e7dd;color:#0f5132}.bars{height:210px;display:flex;align-items:end;gap:7px;border-top:1px solid var(--line);padding-top:18px}.bar{flex:1;min-width:8px;border-radius:5px 5px 0 0}.filters{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:12px}.filters input,.filters select,#pick{height:38px;border:1px solid var(--line);background:var(--card);border-radius:7px;padding:0 10px;min-width:128px}.table{overflow:auto;border:1px solid var(--line);border-radius:8px}table{width:100%;border-collapse:collapse;min-width:900px}th,td{padding:10px 12px;border-bottom:1px solid var(--line);font-size:14px;vertical-align:top}th{background:var(--soft);color:var(--muted);font-size:12px;text-transform:uppercase;text-align:left}.num{text-align:right}.score{width:106px;height:106px;border-radius:50%;display:grid;place-items:center;background:conic-gradient(var(--pri) var(--p),var(--soft) 0);margin:auto}.score span{width:76px;height:76px;border-radius:50%;background:var(--card);display:grid;place-items:center;font-size:24px;font-weight:850}.mnav{display:none;position:fixed;left:0;right:0;bottom:0;z-index:6;background:var(--card);border-top:1px solid var(--line)}.mnav button{flex:1;display:grid;place-items:center;font-size:12px;min-height:58px}.empty{padding:28px 8px;text-align:center;color:var(--muted)}@media(max-width:980px){.nav,.side,#q{display:none}.shell{display:block}main{padding:16px 16px 82px}.mnav{display:flex}.kpis,.c2,.c3,.deep{grid-template-columns:1fr}.wrap,.analysis .wrap{max-width:720px}.head{display:block}h1{font-size:25px}.act{margin-top:12px;flex-wrap:wrap}}@media(max-width:560px){main{padding:14px 12px 82px}.act button,.filters input,.filters select{width:100%}.row{display:block}}</style></head><body><header class=top><div><div class=brand>FinAnalysis</div><nav class=nav id=nav></nav><div class=act><input id=q><button id="langZh">中</button><button id="langEn">EN</button><button id="themeToggle">☾</button></div></div></header><div class=shell><aside class=side><div class=card><b id=profile></b><p class=muted id=meta></p></div><'